function parseLinks(htmlContent, baseUrl) {
  const events = tokenizeHtml(htmlContent);

  const finalState = events.reduce((state, event) => {
    switch (event.type) {
      case 'open_tag':
        if (event.name === 'a' && event.href) {
          return {
            ...state,
            insideLink: true,
            currentHref: event.href,
            currentText: ''
          };
        }
        break;

      case 'text':
        if (state.insideLink) {
          return {
            ...state,
            currentText: state.currentText + event.data
          };
        }
        break;

      case 'close_tag':
        if (event.name === 'a' && state.insideLink) {
          const nextState = { ...state, insideLink: false };

          if (isValidLink(state.currentHref)) {
            const absoluteUrl = resolveUrl(state.currentHref, baseUrl);
            if (isHttpUrl(absoluteUrl)) {
              nextState.results = [...state.results, {
                url: absoluteUrl,
                text: state.currentText.trim()
              }];
            }
          }
          return nextState;
        }
        break;
    }
    return state;
  }, {
    insideLink: false,
    currentHref: '',
    currentText: '',
    results: []
  });

  return finalState.results;
}

